from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram
import time

app = Flask(__name__)

requests_counter = Counter('http_requests_total', help='Total number of HTTP requests')
request_latency_histogram = Histogram('http_request_latencies_bucket',
                                      help='Histogram of request latencies')
request_gauge = Gauge('http_request_status_code',
                      help='Status code of the last HTTP response')

@app.route('/')
def home():
    requests_counter.inc()
    start_time = time.time()
    # Simulate some workload (replace with your business logic)
    time.sleep(0.01)  # 10ms for demonstration purposes
    end_time = time.time()
    request_latency_histogram.observe(end_time - start_time)
    request_gauge.set(200)  # 200 means OK status code
    return "Hello, World!"

if __name__ == "__main__":
    app.run(debug=True)